from typing import List


def separate_paren_groups(paren_string: str) -> List[str]:
    processed = paren_string.replace(' ', '')
    result = []
    start = 0
    balance = 0
    for i, c in enumerate(processed):
        if c == '(':
            balance += 1
        else:
            balance -= 1
        if balance == 0:
            result.append(processed[start:i+1])
            start = i + 1
    return result
